from flask import Flask, request, jsonify
from flask_oauthlib.client import OAuth
from sqlalchemy import create_engine, Table, MetaData

app = Flask(__name__)
app.config['OAUTH_CREDENTIALS'] = {
    'client_id': '<CLIENT_ID>',
    'client_secret': '<CLIENT_SECRET>'
}
oauth = OAuth(app)

# Database setup (replace with your own settings)
engine = create_engine('sqlite:///tokens.db')
metadata = MetaData()
tokens = Table('tokens', metadata, autoload_with=engine)

@oauth.remote_app(name='oauth2_provider')
def oauth2():
    oauth2_provider = oauth.remote_app('oauth2_provider',
                                       base_url='<OAUTH2_PROVIDER_URL>',
                                       request_token_params={'scope': 'read write'},
                                       access_token_method='post')
    return oauth2_provider

@app.route('/login')
def login():
    return oauth2().authorize(callback=oauth2().base_url + '/callback')

@app.route('/callback')
@oauth2().authorized_handler
def callback(base_redirect):
    token = oauth2().tokengetter()
    save_token_to_db(token)  # Add this function to store the token in the database
    return base_redirect(**token)

def save_token_to_db(token):
    metadata.create_all(engine)
    insert_token = tokens.insert().values(
        access_token=token['access_token'],
        refresh_token=token['refresh_token'],
        token_type=token['token_type'],
        expires_at=token['expires']
    )
    engine.execute(insert_token)

def requires_oauth(f):
    def decorated(*args, **kwargs):
        access_token = request.headers.get('Authorization').split()[1]
        if not check_token_in_db(access_token):
            return jsonify({'error': 'Invalid token'}), 401
        return f(*args, **kwargs)
    return decorated

def check_token_in_db(access_token):
    result = engine.execute(tokens.select().where(tokens.c.access_token == access_token)).first()
    return bool(result)

if __name__ == '__main__':
    app.run(debug=True)